// Plotly loader shim. To keep the humblskills binary small, this reports
// falls back to the Plotly CDN when the page is opened. Offline users can
// replace this file at build time with the full plotly.min.js to get a
// truly self-contained report.
(function(){
  if (typeof window.Plotly !== 'undefined') return;
  var s = document.createElement('script');
  s.src = 'https://cdn.plot.ly/plotly-2.35.2.min.js';
  s.async = false;
  document.head.appendChild(s);
})();
